"""Parse MISMO 1003 XML files into structured JSON for pipeline ingestion."""

import json
import os
import xml.etree.ElementTree as ET
from typing import Any, Dict, List, Optional


def _coerce_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _coerce_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _normalize_income_type_token(value: Any) -> str:
    return "".join(ch for ch in str(value or "").strip().lower() if ch.isalnum())


def _is_base_income_type(value: Any) -> bool:
    normalized = _normalize_income_type_token(value)
    return normalized in {
        "base",
        "salary",
        "basesalary",
        "baseemployment",
        "employmentbase",
        "wagesalary",
        "salarywages",
    }


def parse_1003_content_to_json(xml_content: str) -> Dict[str, Any]:
    """Parse 1003 XML content and return a structured JSON payload."""

    try:
        root = ET.fromstring(xml_content)
    except Exception as exc:  # pragma: no cover - defensive
        raise ValueError(f"Failed to parse XML: {exc}") from exc

    # MISMO 3.4 makes heavy use of namespaces. We need to map them.
    ns = {'m': 'http://www.mismo.org/residential/2009/schemas'}

    def get_text(element, path, default=None):
        if element is None:
            return default
        found = element.find(path, ns)
        return found.text if found is not None else default

    def find(element, path):
        if element is None:
            return None
        return element.find(path, ns)

    def findall(element, path) -> List[ET.Element]:
        if element is None:
            return []
        return element.findall(path, ns)

    def first_text(element, paths, default=None):
        for path in paths:
            value = get_text(element, path, None)
            if value is not None and str(value).strip() != "":
                return value
        return default

    def extract_broker_name(root_elem) -> str:
        if root_elem is None:
            return ""
        name_paths = [
            ".//m:LOAN_ORIGINATORS/m:LOAN_ORIGINATOR/m:INDIVIDUAL/m:NAME/m:FullName",
            ".//m:LOAN_ORIGINATORS/m:LOAN_ORIGINATOR/m:LEGAL_ENTITY/m:LEGAL_ENTITY_DETAIL/m:FullName",
            ".//m:ORIGINATORS/m:ORIGINATOR/m:INDIVIDUAL/m:NAME/m:FullName",
            ".//m:ORIGINATORS/m:ORIGINATOR/m:LEGAL_ENTITY/m:LEGAL_ENTITY_DETAIL/m:FullName",
        ]
        name = first_text(root_elem, name_paths, "")
        return str(name or "").strip()

